import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.6ZJjlmu_.js";const u=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"guide/quick-start.md","filePath":"guide/quick-start.md"}'),n={name:"guide/quick-start.md"};function i(s,e,l,h,d,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>This guide gets you from zero to a readable <strong>SUB / INVOKE / UNSUB</strong> timeline in a few minutes.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Unity project with Event Monitor installed (see <a href="./installation.html">Installation</a>).</li><li>You are comfortable entering <strong>Play Mode</strong> in the Editor.</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><h3 id="_1-open-the-event-monitor-window" tabindex="-1">1. Open the Event Monitor window <a class="header-anchor" href="#_1-open-the-event-monitor-window" aria-label="Permalink to &quot;1. Open the Event Monitor window&quot;">​</a></h3><p>Use the menu: <strong>Window → Event Monitor</strong>.</p><h3 id="_2-enable-recording" tabindex="-1">2. Enable recording <a class="header-anchor" href="#_2-enable-recording" aria-label="Permalink to &quot;2. Enable recording&quot;">​</a></h3><p>In the toolbar, ensure <strong>Record</strong> is on (green indicator). When recording is off, new records are not appended.</p><h3 id="_3-enter-play-mode" tabindex="-1">3. Enter Play Mode <a class="header-anchor" href="#_3-enter-play-mode" aria-label="Permalink to &quot;3. Enter Play Mode&quot;">​</a></h3><p>Press <strong>Play</strong> and exercise your game or UI. Event Monitor only captures activity while the Editor is in Play Mode (and while recording is enabled).</p><h3 id="_4-read-the-log-tab" tabindex="-1">4. Read the Log tab <a class="header-anchor" href="#_4-read-the-log-tab" aria-label="Permalink to &quot;4. Read the Log tab&quot;">​</a></h3><p>Open the <strong>Log</strong> tab. You should see rows such as:</p><ul><li><strong>SUB</strong> — something subscribed to an event.</li><li><strong>UNSUB</strong> — something unsubscribed.</li><li><strong>INVOKE</strong> — an instrumented invocation ran (see <a href="./../reference/il-limitations.html">IL patterns and limitations</a> if a fire is missing).</li></ul><p>Use the toggles to filter by action type. Use the search field to narrow by event name, owner type, or subscriber type.</p><h3 id="_5-inspect-subscribers" tabindex="-1">5. Inspect subscribers <a class="header-anchor" href="#_5-inspect-subscribers" aria-label="Permalink to &quot;5. Inspect subscribers&quot;">​</a></h3><p>Open the <strong>Subscribers</strong> tab to see the <strong>current</strong> listener graph: <code>OwnerType :: EventName → SubscriberType :: MethodName</code>.</p><h3 id="_6-try-time-travel-optional" tabindex="-1">6. Try time travel (optional) <a class="header-anchor" href="#_6-try-time-travel-optional" aria-label="Permalink to &quot;6. Try time travel (optional)&quot;">​</a></h3><p>Select a row in the <strong>Log</strong>, enable <strong>Time Travel</strong>, and scrub the slider. Open <strong>Subscribers</strong> again: the graph reflects <strong>subscriber state replayed from SUB/UNSUB only</strong> up to that log position. The log itself does not rewind.</p><h3 id="_7-export-optional" tabindex="-1">7. Export (optional) <a class="header-anchor" href="#_7-export-optional" aria-label="Permalink to &quot;7. Export (optional)&quot;">​</a></h3><p>Choose a format in the toolbar and use <strong>Copy Log</strong> to copy the filtered timeline to the clipboard.</p><h2 id="demo-scene" tabindex="-1">Demo scene <a class="header-anchor" href="#demo-scene" aria-label="Permalink to &quot;Demo scene&quot;">​</a></h2><p>The fastest way to see realistic traffic is the one-click demo:</p><p><strong>Tools → Event Monitor → Generate Demo Scene</strong></p><p>Then Play, click the labeled buttons, and match <strong>INVOKE</strong> lines to the on-screen hints. See <a href="./../how-to/demo-scene.html">Generate the demo scene</a>.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./installation.html">Installation</a></li><li><a href="./../how-to/filtering-and-missing-invoke.html">Filtering and missing INVOKE rows</a></li><li><a href="./../troubleshooting/faq.html">Troubleshooting &amp; FAQ</a></li></ul>',27)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
